  M: [
    { word: 'MARTYR', definition: 'Someone who gives up his or her life in pursuit of a cause, especially a religious one; one who suffers for a cause; one who makes a show of suffering in order to arouse sympathy.', synonyms: ['Sufferer', 'Sacrifice', 'Scapegoat'], antonyms: ['Oppressor', 'Tyrant', 'Persecutor'], sentences: ['Many of the saints were also martyrs; they were executed, often gruesomely, for refusing to renounce their religious beliefs.', 'Eloise played the martyr during hay-fever season, trudging wearily from room to room with a jumbo box of Kleenex in each hand.'] },
    { word: 'MALAISE', definition: 'A feeling of depression, uneasiness, or queasiness.', synonyms: ['Unease', 'Sickness', 'Ailment'], antonyms: ['Well-being', 'Comfort', 'Cheerfulness'], sentences: ['Malaise descended on the calculus class when the teacher announced a quiz.', 'A general feeling of malaise settled over the company after the layoffs were announced.'] },
    { word: 'MAGNATE', definition: 'A rich, powerful, or very successful businessperson.', synonyms: ['Tycoon', 'Baron', 'Mogul'], antonyms: ['Pauper', 'Nobody', 'Minority owner'], sentences: ['John D. Rockefeller was a magnate who was never too cheap to give a shoeshine boy a dime for his troubles.', 'The real estate magnate owned half the buildings downtown.'] },
    { word: 'MANDATE', definition: 'A command or authorization to do something; the will of the voters as expressed by the results of an election.', synonyms: ['Command', 'Order', 'Authorization'], antonyms: ['Option', 'Choice', 'Suggestion'], sentences: ['Our mandate from the executive committee was to find the answer to the problem as quickly as possible.', 'The newly elected president felt that the landslide vote had given him a mandate to do whatever he wanted to do.'] },
    { word: 'MARSHAL', definition: 'To arrange in order; to gather together for the purpose of doing something.', synonyms: ['Organize', 'Assemble', 'Mobilize'], antonyms: ['Disperse', 'Scatter', 'Disarray'], sentences: ['The statistician marshaled his facts before making his presentation.', 'We marshaled half a dozen local groups in opposition to the city council\'s plan to bulldoze our neighborhood.'] },
    { word: 'MARTIAL', definition: 'Warlike; having to do with combat.', synonyms: ['Warlike', 'Military', 'Bellicose'], antonyms: ['Peaceful', 'Civil', 'Civilian'], sentences: ['The parade of soldiers was martial in tone; the soldiers carried rifles and were followed by a formation of tanks.', 'The school principal declared martial law when food riots erupted in the cafeteria.'] },
    { word: 'MANIFEST', definition: 'Visible; evident.', synonyms: ['Obvious', 'Apparent', 'Clear'], antonyms: ['Hidden', 'Unclear', 'Latent'], sentences: ['Daryl\'s anger at us was manifest: You could see it in his expression and hear it in his voice.', 'Rebecca manifested alarm when we told her that the end of her ponytail was on fire, but she didn\'t do anything to put it out.'] },
    { word: 'MALINGER', definition: 'To pretend to be sick to avoid doing work.', synonyms: ['Feign illness', 'Shirk', 'Dodge'], antonyms: ['Work', 'Labor', 'Toil'], sentences: ['Indolent Leon always malingered when it was his turn to clean up the house.', 'Arthur is artful and he always manages to malinger before a big exam.'] },
    { word: 'MITIGATE', definition: 'To make less severe, serious, or painful.', synonyms: ['Alleviate', 'Reduce', 'Lessen'], antonyms: ['Worsen', 'Aggravate', 'Intensify'], sentences: ['The company offered free counseling services to mitigate the stress caused by the recent layoffs.', 'Nothing could mitigate the disappointment he felt after losing the championship game.'] },
    { word: 'MALLEABLE', definition: 'Easy to shape or bend.', synonyms: ['Pliable', 'Ductile', 'Adaptable'], antonyms: ['Inflexible', 'Rigid', 'Intractable'], sentences: ['Modeling clay is very malleable. So is Stuart. We can make him do whatever we want him to do.', 'The lawyer\'s malleable conscience allowed him to defend clients he knew were guilty.'] },
    { word: 'MALIGNANT', definition: 'Causing harm.', synonyms: ['Harmful', 'Vicious', 'Destructive'], antonyms: ['Benign', 'Harmless', 'Beneficial'], sentences: ['Lina has had recurring tumors since the operation; we\'re just glad that none of them have proved malignant.', 'The rumor that spread through the office was a malignant fabrication designed to ruin her career.'] },
    { word: 'MANIFESTO', definition: 'A public declaration of beliefs or principles, usually political ones.', synonyms: ['Declaration', 'Proclamation', 'Platform'], antonyms: ['Secret', 'Whisper', 'Concealment'], sentences: ['The Communist Manifesto was a document that spelled out Karl Marx\'s vision of a Communist world.', 'Jim\'s article about the election was less a piece of reporting than a manifesto of his political views.'] },
    { word: 'MENDACIOUS', definition: 'Not telling the truth; lying.', synonyms: ['Deceitful', 'Untruthful', 'Dishonest'], antonyms: ['Honest', 'Truthful', 'Sincere'], sentences: ['The witness\'s mendacious testimony was quickly exposed by the sharp defense attorney.', 'His mendacious claims about his qualifications cost him the job when the truth came to light.'] },
    { word: 'MACHINATION', definition: 'Scheming activity for an evil purpose.', synonyms: ['Plot', 'Scheme', 'Conspiracy'], antonyms: ['Honesty', 'Frankness', 'Candor'], sentences: ['The ruthless machinations of the mobsters left a trail of blood and bodies.', 'The machinations of the conspirators were aimed at nothing less than the overthrow of the government.'] },
    { word: 'MALFEASANCE', definition: 'An illegal act, especially by a public official.', synonyms: ['Misconduct', 'Impropriety', 'Transgression'], antonyms: ['Integrity', 'Rectitude', 'Uprightness'], sentences: ['President Ford officially pardoned former president Nixon before the latter could be convicted of any malfeasance.', 'The former mayor was indicted for malfeasance related to the misuse of city funds.'] },
    { word: 'MAGNANIMOUS', definition: 'Forgiving; unresentful; noble in spirit; generous.', synonyms: ['Generous', 'Noble', 'Benevolent'], antonyms: ['Petty', 'Vindictive', 'Small-minded'], sentences: ['The boxer was magnanimous in defeat, telling the sports reporters that his opponent had simply been too talented for him to beat.', 'Mrs. Jones magnanimously offered the little boy a cookie when he came over to confess that he had accidentally broken her window while playing baseball.'] },
    { word: 'MATRICULATE', definition: 'To enroll, especially at a college.', synonyms: ['Enroll', 'Register', 'Admit'], antonyms: ['Graduate', 'Withdraw', 'Expel'], sentences: ['Benny told everyone he was going to Harvard, but he actually matriculated to the local junior college.', 'Students must matriculate by the end of August to begin classes in the fall.'] }
],

