  { word: 'NOMINAL', definition: 'In name only; insignificant.', synonyms: ['Titular', 'Token', 'Minimal'], antonyms: ['Real', 'Substantial', 'Significant'], sentences: ['Bert was the nominal chair of the committee, but Sue was the one who ran things.', 'The cost was nominal in comparison with the enormous value of what you received.'] },
  { word: 'NIHILISM', definition: 'The belief that there are no values or morals in the universe.', synonyms: ['Skepticism', 'Pessimism', 'Negativism'], antonyms: ['Belief', 'Optimism', 'Moralism'], sentences: ['A nihilist does not believe in any objective standards of right or wrong.', 'The terrorist attack was an act of extreme nihilism, demonstrating a total disregard for human life and value.'] },
  { word: 'NEPOTISM', definition: 'Showing favoritism to friends or family in business or politics.', synonyms: ['Favoritism', 'Bias', 'Cronyism'], antonyms: ['Impartiality', 'Fairness', 'Meritocracy'], sentences: ['Clarence had no business acumen, so he was counting on nepotism when he married the boss\'s daughter.', 'The public criticized the senator for his blatant nepotism in hiring his relatives for high-paying positions.'] },
  { word: 'NEBULOUS', definition: 'Vague; hazy; indistinct.', synonyms: ['Vague', 'Hazy', 'Fuzzy'], antonyms: ['Clear', 'Distinct', 'Sharp'], sentences: ['Oscar\'s views are so nebulous that no one can figure out what he thinks about anything.', 'The community\'s boundaries are somewhat nebulous; where they are depends on whom you ask.'] },
  { word: 'NEFARIOUS', definition: 'Evil; flagrantly wicked.', synonyms: ['Wicked', 'Evil', 'Iniquitous'], antonyms: ['Virtuous', 'Good', 'Righteous'], sentences: ['The radicals\' nefarious plot was to destroy New York by filling the reservoirs with strawberry Jell-O.', 'The convicted murderer had committed a myriad of nefarious acts.'] },
  { word: 'NEOLOGISM', definition: 'A new word or phrase; a new usage of a word.', synonyms: ['New word', 'Coinage', 'Innovation'], antonyms: ['Archaism', 'Old word', 'Traditional term'], sentences: ['Pedants don\'t like neologisms. They like the words we already have.', 'The word "blog" was once a neologism, but it is now common usage.'] },
  { word: 'NOSTALGIA', definition: 'Sentimental longing for the past; homesickness.', synonyms: ['Homesickness', 'Wistfulness', 'Reminiscence'], antonyms: ['Anticipation', 'Forward-looking', 'Present-mindedness'], sentences: ['A wave of nostalgia overcame me when the old Biggie Smalls song came on the radio; hearing it took me right back to 1997.', 'As we talked about the fun we\'d had together in junior high school, we all began to feel a little nostalgic.'] },
  { word: 'NOTORIOUS', definition: 'Famous for something bad.', synonyms: ['Infamous', 'Scandalous', 'Disreputable'], antonyms: ['Reputable', 'Honorable', 'Unknown'], sentences: ['No one wanted to play poker with Jeremy because he was a notorious cheater.', 'Jesse\'s notoriety as a bank robber made it difficult for him to find a job in banking.'] },
  { word: 'NARCISSISM', definition: 'Excessive love of one\'s body or oneself.', synonyms: ['Self-love', 'Vanity', 'Egoism'], antonyms: ['Selflessness', 'Humility', 'Altruism'], sentences: ['Throwing a kiss to your reflection in the mirror is an act of narcissism—so is filling your living room with all your bowling trophies.', 'The selfish students were bound up in narcissistic concerns and gave no thought to other people.'] }
